// ============ КОМПОНЕНТЫ ============

function Dot({ color }) {
  return <span style={{ width: 6, height: 6, borderRadius: 6, background: color, display: "inline-block", flexShrink: 0 }} />;
}

function ItemIcon({ item, hue, open }) {
  return (
    <div style={{
      width: 40, height: 40, flexShrink: 0, borderRadius: 11,
      background: open ? hexA(hue, 0.16) : hexA(hue, 0.085),
      border: `1px solid ${hexA(hue, open ? 0.55 : 0.22)}`,
      display: "flex", alignItems: "center", justifyContent: "center",
      transition: "background .2s, border-color .2s",
    }}>
      <svg viewBox="0 0 24 24" width="22" height="22" aria-hidden style={{ color: hue, display: "block" }}
           fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
        {ICONS[item.name] || ICONS._default}
      </svg>
    </div>
  );
}

function ItemCard({ item, hue }) {
  const [open, setOpen] = useState(false);
  const toggle = () => setOpen(o => !o);
  return (
    <div
      className="pi-card"
      role="button"
      tabIndex={0}
      aria-expanded={open}
      aria-label={item.name}
      onClick={toggle}
      onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); toggle(); } }}
      style={{
        "--hue": hue,
        background: "#FFFFFF",
        border: "1px solid #E9E5DC",
        borderLeft: open ? `3px solid ${hue}` : "1px solid #E9E5DC",
        borderRadius: 14,
        padding: open ? "15px 17px 16px 15px" : "15px 17px",
        cursor: "pointer",
        boxShadow: open ? "0 6px 24px rgba(35,34,42,0.07)" : "none",
      }}
    >
      <div style={{ display: "flex", gap: 12, alignItems: "flex-start" }}>
        <ItemIcon item={item} hue={hue} open={open} />
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ display: "flex", justifyContent: "space-between", gap: 10, alignItems: "flex-start" }}>
            <div style={{ fontWeight: 600, fontSize: 15.5, color: "#23222A", lineHeight: 1.32 }}>
              {item.name}
              {item.body && (
                <span style={{ marginLeft: 8, fontSize: 10.5, fontWeight: 600, color: "#8A8794", border: "1px solid #DDD9CF", borderRadius: 10, padding: "1px 7px", verticalAlign: "2px", letterSpacing: "0.04em" }}>
                  {BODY[item.body]}
                </span>
              )}
            </div>
            <div className="pi-toggle" aria-hidden style={{
              width: 26, height: 26, flexShrink: 0, borderRadius: 13,
              border: open ? `1px solid ${hue}` : "1px solid #DDD9CF",
              background: open ? hue : "#FBFAF6",
              color: open ? "#FFFFFF" : "#A9A599",
              display: "flex", alignItems: "center", justifyContent: "center",
              fontSize: 17, lineHeight: 1,
              transform: open ? "rotate(45deg)" : "none",
              transition: "transform .2s, background .2s, color .2s, border-color .2s",
            }}>+</div>
          </div>
          <div style={{ fontSize: 13.5, color: "#6E6B78", marginTop: 4, lineHeight: 1.5 }}>{item.desc}</div>
        </div>
      </div>
      {open && (
        <div style={{ fontSize: 13.5, color: "#403E48", marginTop: 12, lineHeight: 1.66, borderTop: "1px solid #F0EDE5", paddingTop: 12 }}>
          {item.details}
        </div>
      )}
      <div style={{ display: "flex", gap: 12, marginTop: 12, flexWrap: "wrap", alignItems: "center" }}>
        {item.who.map(w => (
          <span key={w} style={{ display: "inline-flex", alignItems: "center", gap: 5, fontSize: 11.5, color: "#8A8794", fontWeight: 550 }}>
            <Dot color={WHO[w].color} />{WHO[w].label.toLowerCase()}
          </span>
        ))}
        <span style={{ color: "#DDD9CF" }}>·</span>
        {item.channels.map(c => (
          <span key={c} style={{ display: "inline-flex", alignItems: "center", gap: 5, fontSize: 11.5, color: "#8A8794" }}>
            <Dot color={CHANNELS[c].color} />{CHANNELS[c].label}
          </span>
        ))}
      </div>
    </div>
  );
}

function ZoneLocator({ pos, hue, place }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 6 }}>
      <div style={{ position: "relative", width: 84, height: 8, flexShrink: 0 }}>
        <div style={{ position: "absolute", top: 3.5, left: 0, right: 0, height: 1, background: "#DAD6CB" }} />
        {pos !== null ? (
          <div style={{ position: "absolute", top: 0, left: `calc(${pos * 100}% - 4px)`, width: 8, height: 8, borderRadius: 8, background: hue }} />
        ) : (
          <div style={{ position: "absolute", top: 2.5, left: 0, right: 0, height: 3, borderRadius: 3, background: hue, opacity: 0.45 }} />
        )}
      </div>
      <span style={{ fontSize: 11, letterSpacing: "0.16em", textTransform: "uppercase", color: "#9B97A3", fontWeight: 550 }}>{place}</span>
    </div>
  );
}

function App() {
  const [whoFilter, setWhoFilter] = useState(null);
  const [chFilter, setChFilter] = useState(null);
  const [hiBody, setHiBody] = useState(null); // анатомия стороны роста: 'f' | 'm' | null
  const [loBody, setLoBody] = useState(null); // анатомия стороны спада

  const bodyOk = (item) => {
    if (!item.body) return true;
    if (whoFilter === "me") return !hiBody || hiBody === item.body;
    if (whoFilter === "alina") return !loBody || loBody === item.body;
    const set = [hiBody, loBody].filter(Boolean);
    if (set.length < 2) return true;
    return set.includes(item.body);
  };

  const filtered = useMemo(() => {
    return ZONES.map(z => ({
      ...z,
      items: z.items.filter(it =>
        (!whoFilter || it.who.includes(whoFilter)) &&
        (!chFilter || it.channels.includes(chFilter)) &&
        bodyOk(it)
      ),
    })).filter(z => z.items.length > 0);
  }, [whoFilter, chFilter, hiBody, loBody]);

  const total = useMemo(() => filtered.reduce((s, z) => s + z.items.length, 0), [filtered]);
  const grandTotal = ZONES.reduce((s, z) => s + z.items.length, 0);
  const anyFilter = whoFilter || chFilter || hiBody || loBody;

  const pill = (active, activeColor) => ({
    padding: "7px 15px", borderRadius: 22, fontSize: 13, cursor: "pointer", fontWeight: 550,
    background: active ? (activeColor || "#23222A") : "#F0EDE5",
    color: active ? "#FBFAF6" : "#55525E",
    border: "1px solid transparent",
    transition: "background .15s, color .15s",
  });

  const bodyBtn = (active, roleColor) => ({
    padding: "4px 12px", borderRadius: 16, fontSize: 12.5, cursor: "pointer", fontWeight: 600,
    background: active ? roleColor : "transparent",
    color: active ? "#FBFAF6" : "#7A7784",
    border: `1px solid ${active ? roleColor : "#DDD9CF"}`,
    transition: "all .15s",
  });

  return (
    <div style={{ minHeight: "100vh", background: "#FAF8F4", color: "#23222A", fontFamily: "'Onest', -apple-system, sans-serif" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Onest:wght@400;500;600;700&family=Spectral:ital,wght@1,400;1,500&display=swap&subset=cyrillic');
        * { box-sizing: border-box; }
        ::selection { background: #C2566F33; }
        .wave { animation-timing-function: linear; animation-iteration-count: infinite; }
        .wave-a { animation-name: drift; animation-duration: 34s; }
        .wave-b { animation-name: drift; animation-duration: 52s; }
        @keyframes drift { from { transform: translateX(0); } to { transform: translateX(-1200px); } }
        @media (prefers-reduced-motion: reduce) { .wave { animation: none; } }
        button:focus-visible { outline: 2px solid #23222A; outline-offset: 2px; }
        .pi-card { transition: border-color .18s, box-shadow .18s, transform .18s; }
        .pi-card:hover { border-color: var(--hue) !important; box-shadow: 0 7px 22px rgba(35,34,42,0.09) !important; transform: translateY(-1px); }
        .pi-card:hover .pi-toggle { border-color: var(--hue); color: var(--hue); }
        .pi-card:focus-visible { outline: 2px solid var(--hue); outline-offset: 2px; }
        .pi-card:active { transform: translateY(0); }
        @media (hover: none) { .pi-card .pi-toggle { border-color: var(--hue); color: var(--hue); } }
      `}</style>

      <div style={{ maxWidth: 880, margin: "0 auto", padding: "52px 20px 90px" }}>

        <div style={{ fontSize: 11.5, letterSpacing: "0.22em", textTransform: "uppercase", color: "#9B97A3", marginBottom: 14 }}>
          карта для пар в периоды рассинхрона желания · {grandTotal} вариантов
        </div>
        <h1 style={{ fontSize: "clamp(40px, 7vw, 60px)", fontWeight: 700, margin: "0 0 22px", lineHeight: 1.04, letterSpacing: "-0.02em" }}>
          Поле игры
        </h1>

        <Tides />
        <p style={{ fontFamily: "'Spectral', serif", fontStyle: "italic", fontSize: 16.5, color: "#55525E", margin: "0 0 30px", lineHeight: 1.5 }}>
          Два желания редко движутся в одной фазе. Это не поломка — это рост и спад.
        </p>

        <p style={{ fontSize: 16, lineHeight: 1.68, color: "#403E48", maxWidth: 640, margin: "0 0 12px" }}>
          Почти в любых длинных романтических отношениях — независимо от формата, будь то моногамия,
          открытая пара или что-то своё — случаются периоды, когда у одного желание на подъёме,
          а у другого на спаде. Это не охлаждение чувств и ничья не вина: два живых ритма
          просто редко совпадают идеально.
        </p>
        <p style={{ fontSize: 16, lineHeight: 1.68, color: "#403E48", maxWidth: 640, margin: "0 0 40px" }}>
          Эта карта — полное поле возможностей для такого периода: от практик наедине с собой
          до вариантов, требующих серьёзных договорённостей. Она не план действий и не список
          рекомендаций. Смысл — видеть поле целиком, изучать его вдвоём и пробовать элементы
          осознанно, а не из дефицита. Часто синхронизация начинается уже с того,
          что оба смотрят на одну и ту же карту.
        </p>

        <div style={{ fontSize: 11, letterSpacing: "0.18em", textTransform: "uppercase", color: "#9B97A3", marginBottom: 10, fontWeight: 550 }}>чьё это поле</div>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 10 }}>
          {Object.entries(WHO).map(([k, v]) => (
            <button key={k} onClick={() => setWhoFilter(whoFilter === k ? null : k)} style={pill(whoFilter === k, v.color)}>
              {v.label}
            </button>
          ))}
        </div>
        <p style={{ fontSize: 13, color: "#8A8794", lineHeight: 1.6, maxWidth: 560, margin: "0 0 22px" }}>
          Рост — тот, чьё желание сейчас активнее. Спад — тот, чьё тише.
          Роли временные: в долгих отношениях партнёры обычно успевают побывать в обеих.
        </p>

        <div style={{ fontSize: 11, letterSpacing: "0.18em", textTransform: "uppercase", color: "#9B97A3", marginBottom: 10, fontWeight: 550 }}>конфигурация пары · необязательно</div>
        <div style={{ display: "flex", gap: 22, flexWrap: "wrap", marginBottom: 10, alignItems: "center" }}>
          <div style={{ display: "flex", gap: 7, alignItems: "center" }}>
            <span style={{ fontSize: 13, color: "#55525E", fontWeight: 550 }}>Рост:</span>
            <button onClick={() => setHiBody(hiBody === "f" ? null : "f")} style={bodyBtn(hiBody === "f", WHO.me.color)}>Ж</button>
            <button onClick={() => setHiBody(hiBody === "m" ? null : "m")} style={bodyBtn(hiBody === "m", WHO.me.color)}>М</button>
          </div>
          <div style={{ display: "flex", gap: 7, alignItems: "center" }}>
            <span style={{ fontSize: 13, color: "#55525E", fontWeight: 550 }}>Спад:</span>
            <button onClick={() => setLoBody(loBody === "f" ? null : "f")} style={bodyBtn(loBody === "f", WHO.alina.color)}>Ж</button>
            <button onClick={() => setLoBody(loBody === "m" ? null : "m")} style={bodyBtn(loBody === "m", WHO.alina.color)}>М</button>
          </div>
        </div>
        <p style={{ fontSize: 13, color: "#8A8794", lineHeight: 1.6, maxWidth: 560, margin: "0 0 22px" }}>
          Отметьте анатомию каждой стороны — и карта скроет нерелевантные предметы.
          Карточки с пометкой «жен.» / «муж.» привязаны к анатомии, всё остальное универсально.
        </p>

        <div style={{ fontSize: 11, letterSpacing: "0.18em", textTransform: "uppercase", color: "#9B97A3", marginBottom: 10, fontWeight: 550 }}>канал восприятия</div>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 14 }}>
          {Object.entries(CHANNELS).map(([k, v]) => (
            <button key={k} onClick={() => setChFilter(chFilter === k ? null : k)} style={pill(chFilter === k, v.color)}>
              {v.label}
            </button>
          ))}
        </div>

        <div style={{ fontSize: 13, color: "#8A8794", marginBottom: 40 }}>
          {anyFilter ? `показано ${total} из ${grandTotal}` : `все ${grandTotal} вариантов`}
          {anyFilter && (
            <button onClick={() => { setWhoFilter(null); setChFilter(null); setHiBody(null); setLoBody(null); }}
              style={{ marginLeft: 12, background: "none", border: "none", color: "#C2566F", cursor: "pointer", fontSize: 13, textDecoration: "underline", padding: 0 }}>
              сбросить
            </button>
          )}
        </div>

        {filtered.map(zone => (
          <section key={zone.id} style={{ marginBottom: 54 }}>
            <ZoneLocator pos={zone.pos} hue={zone.hue} place={zone.place} />
            <h2 style={{ fontSize: 26, fontWeight: 650, margin: "0 0 8px", letterSpacing: "-0.015em" }}>
              {zone.title}
            </h2>
            <p style={{ fontSize: 14, color: "#6E6B78", margin: "0 0 20px", lineHeight: 1.6, maxWidth: 620 }}>
              {zone.subtitle}
            </p>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(276px, 1fr))", gap: 12 }}>
              {zone.items.map(it => <ItemCard key={it.name} item={it} hue={zone.hue} />)}
            </div>
          </section>
        ))}

        <div style={{ marginTop: 64, paddingTop: 28, borderTop: "1px solid #E5E1D6", maxWidth: 640 }}>
          <div style={{ fontFamily: "'Spectral', serif", fontStyle: "italic", fontSize: 20, color: "#403E48", marginBottom: 12 }}>
            Как этим пользоваться вдвоём
          </div>
          <p style={{ fontSize: 14, lineHeight: 1.7, color: "#6E6B78", margin: "0 0 10px" }}>
            Каждую карточку можно раскрыть нажатием — внутри подробности. Фильтры показывают срезы:
            чьё это поле, какая анатомия у сторон и через какой канал восприятия работает вариант.
          </p>
          <p style={{ fontSize: 14, lineHeight: 1.7, color: "#6E6B78", margin: 0 }}>
            Рабочий формат: каждый проходит карту отдельно и помечает про себя пункты —
            «да», «любопытно», «точно нет». Потом сравнить и посмотреть на зоны совпадения.
            Обсуждать пункты на экране легче, чем говорить о желаниях напрямую, —
            в этом и смысл карты как предмета. А поскольку рост и спад со временем
            меняются местами, к карте можно возвращаться из обеих ролей.
          </p>
        </div>

        <footer style={{ marginTop: 44, paddingTop: 24, borderTop: "1px solid #E5E1D6", maxWidth: 660 }}>
          <div style={{ fontSize: 11, letterSpacing: "0.18em", textTransform: "uppercase", color: "#9B97A3", marginBottom: 12, fontWeight: 550 }}>
            18+ · важное уточнение
          </div>
          <p style={{ fontSize: 12.5, lineHeight: 1.65, color: "#8A8794", margin: "0 0 9px" }}>
            Материал предназначен для совершеннолетних (18+) и носит информационно-просветительский
            и художественный характер. Это личный некоммерческий проект — обзор существующего поля практик,
            а не услуга, не реклама, не публичная оферта и не побуждение к каким-либо действиям, покупкам
            или образу жизни.
          </p>
          <p style={{ fontSize: 12.5, lineHeight: 1.65, color: "#8A8794", margin: "0 0 9px" }}>
            Это не медицинская, психотерапевтическая, сексологическая или иная профессиональная помощь,
            не диагностика и не лечение, не индивидуальная рекомендация. Материал описывает существующие
            практики, но не пропагандирует и не навязывает какие-либо сексуальные отношения, ориентацию или
            образ жизни, не адресован несовершеннолетним и не призывает к каким-либо действиям. По вопросам
            здоровья, психики и отношений обращайтесь к квалифицированным специалистам.
          </p>
          <p style={{ fontSize: 12.5, lineHeight: 1.65, color: "#8A8794", margin: 0 }}>
            Любые практики — под личную ответственность взрослых участников, при обоюдном информированном
            согласии и с соблюдением законодательства вашей страны. Автор не несёт ответственности за решения
            и последствия применения материала.
          </p>
        </footer>
      </div>
    </div>
  );
}


const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(React.createElement(App));
